where
    C: ConnectionTrait,
{
    let now = unix_now()?;
    let generation = new_cleanup_generation()?;
    entities::repo_storage_cleanup_job::Entity::insert(
        entities::repo_storage_cleanup_job::Model::from_domain(&cleanup, generation, now)
            .into_active_model(),
    )
