    51	    pub fn run_ready_outbox_jobs(
    52	        &self,
    53	        worker_id: &str,
    54	        limit: usize,
    55	    ) -> Result<OutboxRunSummary, ApiError> {
    56	        if limit == 0 {
    57	            return Ok(OutboxRunSummary::default());
    58	        }
    59	
    60	        match self.inner.as_ref() {
    61	            MetadataStoreInner::Postgres { db, runtime } => {
    62	                let db = Arc::clone(db);
    63	                let worker_id = worker_id.to_string();
    64	                run_api_db_on(runtime, async move {
    65	                    let mut summary = OutboxRunSummary::default();
    66	                    for _ in 0..limit {
    67	                        let Some(job) =
    68	                            claim_next_ready_job(db.as_ref(), &worker_id, DEFAULT_JOB_LEASE_SECS)
    69	                                .await?
    70	                        else {
    71	                            break;
    72	                        };
    73	                        summary.claimed += 1;
    74	
    75	                        match execute_outbox_job(db.as_ref(), &job).await {
    76	                            Ok(()) => {
    77	                                complete_outbox_job(db.as_ref(), &job, &worker_id).await?;
    78	                                summary.completed += 1;
    79	                            }
    80	                            Err(error) => {
    81	                                let message = error.message;
    82	                                let attempts = next_retry_attempt(job.attempts);
    83	                                if is_terminal_retry_attempt(attempts) {
    84	                                    tracing::error!(
    85	                                        job_id = %job.id,
    86	                                        kind = %job.kind,
    87	                                        attempts,
    88	                                        max_attempts = MAX_JOB_ATTEMPTS,
    89	                                        error = %message,
    90	                                        "outbox job exhausted retries; marking failed"
    91	                                    );
    92	                                } else {
    93	                                    tracing::warn!(
    94	                                        job_id = %job.id,
    95	                                        kind = %job.kind,
    96	                                        attempts,
    97	                                        max_attempts = MAX_JOB_ATTEMPTS,
    98	                                        next_retry_delay_secs = retry_delay_seconds(attempts),
    99	                                        error = %message,
   100	                                        "outbox job failed; scheduling retry"
   101	                                    );
   102	                                }
   103	                                fail_outbox_job(db.as_ref(), &job, &worker_id, message).await?;
   104	                                summary.failed += 1;
   105	                            }
   106	                        }
   107	                    }
   108	                    Ok(summary)
   109	                })
   110	            }
