    88	fn create_table_statement(table: &TableSpec) -> TableCreateStatement {
    89	    let mut statement = Table::create();
    90	    statement.table(SchemaIden::new(table.name)).if_not_exists();
    91	
    92	    let inline_primary_key = table.inline_primary_key_column();
    93	    for column in table.columns {
    94	        statement.col(column_definition(
    95	            column,
    96	            inline_primary_key == Some(column.name),
    97	        ));
    98	    }
    99	
   100	    if let PrimaryKeySpec::Composite { name, columns } = table.primary_key {
   101	        let mut primary_key = Index::create();
   102	        primary_key.name(name);
   103	        for column in columns.iter().copied() {
   104	            primary_key.col(SchemaIden::new(column));
   105	        }
   106	        statement.primary_key(&mut primary_key);
   107	    }
   108	
   109	    for foreign_key in table.foreign_keys {
   110	        let mut foreign_key = foreign_key_statement(table.name, foreign_key);
   111	        statement.foreign_key(&mut foreign_key);
   112	    }
   113	
   114	    statement
   115	}
