   119	    match column.column_type {
   120	        ColumnType::BigInteger => {
   121	            definition.big_integer();
   122	        }
   123	        ColumnType::Boolean => {
   124	            definition.boolean();
   125	        }
   126	        ColumnType::Integer => {
   127	            definition.integer();
   128	        }
   129	        ColumnType::JsonBinary => {
   130	            definition.json_binary();
   131	        }
   132	        ColumnType::String => {
   133	            definition.string();
   134	        }
   135	        ColumnType::Text => {
   136	            definition.text();
   137	        }
   138	    }
   139	
   140	    if !column.nullable {
   141	        definition.not_null();
   142	    }
   143	    if primary_key {
   144	        definition.primary_key();
   145	    }
   146	    if column.unique {
   147	        definition.unique_key();
   148	    }
   149	
   150	    definition
   151	}
